solution_code:
#include <iostream>

int safeSqrt(int n) {
    if (n < 0) return -1;
    int root = 0;
    while (root * root < n)
        ++root;
    if (root * root == n)
        return root;
    return -1;
}

int main() {
    int n;
    std::cin >> n;

    int result = safeSqrt(n);
    if (result == -1) {
        if (n < 0)
            std::cout << "Error: negative input\n";
        else
            std::cout << "Error: not a perfect square\n";
    } else {
        std::cout << "Result: " << result << '\n';
    }
    return 0;
}

