solution_code:
#include <iostream>

int safeModulo(int a, int b) {
    if (b == 0) return -1;
    return a % b;
}

int main() {
    int a, b;
    std::cin >> a >> b;

    int result = safeModulo(a, b);
    if (b == 0)
        std::cout << "Error: modulo by zero\n";
    else
        std::cout << "Result: " << result << '\n';
    return 0;
}
